// Bemenő adatok feldolgozása a webhook-ból
// A webhook JSON body-jából kiolvassuk a kérés paramétereit

const input = $input.all()[0].json;

// Alapértelmezett értékek beállítása
const projectType = input.projectType || 'landing_page';
const businessName = input.businessName || 'My Business';
const language = input.language || $env.GRAVITY_DEFAULT_LANGUAGE || 'hu';
const description = input.description || '';
const pages = input.pages || ['home', 'about', 'contact'];
const designStyle = input.designStyle || 'modern';

return {
  businessName,
  projectType,
  language,
  description,
  pages,
  designStyle
};

// DeepSeek API prompt összeállítása Gravity CMS fájlok generálásához
const data = $input.all()[0].json;

const prompt = `You are a Gravity CMS expert. Generate a complete Gravity CMS website structure for a ${data.projectType} project.

Business/Project Name: ${data.businessName}
Description: ${data.description}
Language: ${data.language}
Design Style: ${data.designStyle}
Required Pages: ${data.pages.join(', ')}

Please generate the following Gravity CMS files. Output MUST be valid JSON with this exact structure:

{
  "pages": {
    "home": {
      "template": "default",
      "route": "/",
      "title": "page title in ${data.language}",
      "content": {
        "hero": {
          "title": "compelling hero title in ${data.language}",
          "subtitle": "subtitle in ${data.language}",
          "cta_text": "call to action in ${data.language}",
          "cta_link": "/contact"
        },
        "sections": [
          {
            "type": "features|testimonials|pricing|gallery|text",
            "title": "section title in ${data.language}",
            "content": "section content in ${data.language}"
          }
        ]
      },
      "meta": {
        "title": "SEO title in ${data.language}",
        "description": "SEO description in ${data.language}"
      }
    }
  },
  "config": {
    "system": {
      "site_name": "${data.businessName}",
      "language": "${data.language}",
      "timezone": "Europe/Budapest"
    },
    "theme": {
      "name": "${data.designStyle}",
      "primary_color": "#hexcolor",
      "secondary_color": "#hexcolor",
      "font_family": "suggested Google Font"
    },
    "plugins": ["suggested-gravity-plugins"]
  },
  "admin_structure": {
    "blueprints": {},
    "forms": []
  }
}

Make the content professional, SEO-optimized, and tailored for the ${data.language} language market. Use realistic, industry-appropriate content.`;

return { prompt };

