// DeepSeek válasz feldolgozása és Gravity CMS struktúra kinyerése
const response = $input.all()[0].json;

let content;
try {
  // A DeepSeek válasz a choices[0].message.content mezőben van
  const aiResponse = response.choices[0].message.content;

  // Parse-oljuk a JSON-t (a model lehet, hogy markdown code block-ként adja vissza)
  let jsonStr = aiResponse;
  if (jsonStr.includes('```json')) {
    jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
  } else if (jsonStr.includes('```')) {
    jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
  }

  content = JSON.parse(jsonStr);
} catch (e) {
  // Ha nem sikerül parse-olni, használjuk a nyers választ
  content = { error: "Failed to parse AI response", raw: response.choices[0].message.content };
}

return {
  generated: content,
  timestamp: new Date().toISOString(),
  model: response.model || 'deepseek-chat',
  usage: response.usage || {}
};
